import redis
from datetime import timedelta, datetime

class RedisService(object):
    def __init__(self, nodes=['localhost:6379']):
        self._conn = None
        try:
            # Assuming a simple single node setup for simplicity. In production environments, multiple nodes should be set up as part of a cluster and each with their own unique TTLs 
            self._conn = redis.Redis(host=nodes[0].split(':')[0], port=int(nodes[0].split(':')[1]), db=0)
        except Exception as e:
            print("Failed to connect with error {}".format(str(e))) 
        
    def set_data(self, key, value, ttl_seconds):
        if not self._conn:
            return None
        
        try:
            # Redis Pipeline is used for saving bandwidth and speeding up the response time. It sends multiple commands at once to reduce round trips.
            pipe = self._conn.pipeline(transaction=True) 
            
            # Set data in Redis with a TTL value.
            pipe.set(key, value, ex=ttl_seconds) 

            # Execute the command on redis
            pipe.execute()  
        except Exception as e:
            print("Failed to set key-value pair with error {}".format(str(e)))
            
    def get_data(self, key):
        if not self._conn:
            return None
        
        try:
            # Fetch the value for a given key from Redis.
            data = self._conn.get(key) 

            # If key does not exist then `None` will be returned.
            return data if data else None   
        except Exception as e:
            print("Failed to fetch key-value pair with error {}".format(str(e)))